// Procesar datos recibidos de Kapso
const payload = $input.first().json;

// Extraer datos del reclamo
const reclamoData = payload.reclamo_data;

// Generar ID único para el ticket
const ticketId = `REC-${Date.now()}-${Math.random().toString(36).substr(2, 5).toUpperCase()}`;

// Preparar datos para Supabase
const dbData = {
  ticket_id: ticketId,
  nombre: reclamoData.nombre,
  email: reclamoData.email,
  producto: reclamoData.producto,
  motivo: reclamoData.motivo,
  descripcion: reclamoData.descripcion,
  conversation_id: reclamoData.conversation_id,
  user_phone: reclamoData.user_phone,
  status: 'nuevo',
  priority: 'media',
  created_at: new Date().toISOString(),
  source: 'whatsapp_kapso'
};

// Preparar datos para Jira
const jiraData = {
  fields: {
    project: { key: 'SUP' },
    summary: `Reclamo WhatsApp: ${reclamoData.producto}`,
    description: {
      type: 'doc',
      version: 1,
      content: [
        {
          type: 'paragraph',
          content: [
            { type: 'text', text: `Cliente: ${reclamoData.nombre}` }
          ]
        },
        {
          type: 'paragraph', 
          content: [
            { type: 'text', text: `Email: ${reclamoData.email}` }
          ]
        },
        {
          type: 'paragraph',
          content: [
            { type: 'text', text: `Producto: ${reclamoData.producto}` }
          ]
        },
        {
          type: 'paragraph',
          content: [
            { type: 'text', text: `Motivo: ${reclamoData.motivo}` }
          ]
        },
        {
          type: 'paragraph',
          content: [
            { type: 'text', text: `Descripción: ${reclamoData.descripcion}` }
          ]
        }
      ]
    },
    issuetype: { name: 'Bug' },
    priority: { name: 'Medium' },
    labels: ['whatsapp', 'reclamo', 'kapso']
  }
};

// Preparar notificación para Slack
const slackData = {
  text: `🚨 Nuevo Reclamo WhatsApp`,
  blocks: [
    {
      type: 'header',
      text: {
        type: 'plain_text',
        text: '🚨 Nuevo Reclamo WhatsApp'
      }
    },
    {
      type: 'section',
      fields: [
        {
          type: 'mrkdwn',
          text: `*Ticket ID:*\n${ticketId}`
        },
        {
          type: 'mrkdwn', 
          text: `*Cliente:*\n${reclamoData.nombre}`
        },
        {
          type: 'mrkdwn',
          text: `*Email:*\n${reclamoData.email}`
        },
        {
          type: 'mrkdwn',
          text: `*Producto:*\n${reclamoData.producto}`
        }
      ]
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Motivo:* ${reclamoData.motivo}\n*Descripción:* ${reclamoData.descripcion}`
      }
    }
  ]
};

return [
  {
    json: {
      ticketId,
      originalPayload: payload,
      dbData,
      jiraData,
      slackData
    }
  }
];

// Preparar respuesta para Kapso
const ticketId = $('data-processor').first().json.ticketId;
const jiraResponse = $('jira-create-ticket').first().json;

// Extraer el ID del ticket de Jira si existe
const jiraTicketId = jiraResponse?.key || null;

// Respuesta exitosa para Kapso
const kapsoResponse = {
  success: true,
  reclamo_id: ticketId,
  jira_ticket: jiraTicketId,
  message: 'Reclamo procesado exitosamente',
  timestamp: new Date().toISOString()
};

return [{ json: kapsoResponse }];

// Nodo de debugging para logs
const input = $input.first().json;

console.log('=== RECLAMO PROCESSOR DEBUG ===');
console.log('Timestamp:', new Date().toISOString());
console.log('Input Data:', JSON.stringify(input, null, 2));
console.log('Ticket ID Generated:', input.ticketId);
console.log('================================');

// Pasar datos sin modificar
return [{ json: input }];
